{"content":"     1	import SwiftUI
     2	
     3	/// App entry point. A small launcher window opens the full immersive space, which
     4	/// IS the experience (no passthrough). Spec: §1, §7.
     5	@main
     6	struct FloatApp: App {
     7	    @State private var model = AppModel()
     8	
     9	    var body: some Scene {
    10	        WindowGroup(id: "launcher") {
    11	            LauncherView()
    12	                .environment(model)
    13	        }
    14	        .windowResizability(.contentSize)
    15	
    16	        ImmersiveSpace(id: AppModel.immersiveSpaceID) {
    17	            ImmersiveView()
    18	                .environment(model)
    19	        }
    20	        // §1 — full immersion, everything else out of the way.
    21	        .immersionStyle(selection: .constant(.full), in: .full)
    22	    }
    23	}
    24	","filePath":"Float/Float/App/FloatApp.swift","fileSize":677,"linesRead":24,"startLine":1,"totalLines":24}

