{"content":"     1	import RealityKit
     2	
     3	/// Assembles the layered depth scene (§3) from an EnvironmentConfig (§7a).
     4	/// Every layer is a child of one stationary root at the origin (§9: camera never moves).
     5	enum SceneBuilder {
     6	    static func build(config: EnvironmentConfig, clock: AnimationClock) -> Entity {
     7	        let root = Entity()
     8	        root.name = "UniverseRoot"
     9	
    10	        let gen = EnvironmentGenerator(config: config)
    11	
    12	        root.addChild(FarBackdrop.make(gen: gen))       // L1 §4
    13	        root.addChild(NebulaVolume.make(gen: gen))      // L2 nebula (splat / particle fallback)
    14	        root.addChild(StarVolume.make(gen: gen))        // L3 — the depth workhorse
    15	        root.addChild(PhenomenaSpawner.make(gen: gen))  // L4 §6
    16	
    17	        if let body = config.body {
    18	            root.addChild(CelestialBodies.make(body, gen: gen))          // §7c
    19	        }
    20	        if let field = config.asteroidField {
    21	            root.addChild(AsteroidField.make(field, gen: gen))           // §7d
    22	        }
    23	        return root
    24	    }
    25	}
    26	","filePath":"Float/Float/Immersive/SceneBuilder.swift","fileSize":1020,"linesRead":26,"startLine":1,"totalLines":26}

