{"content":"     1	import RealityKit
     2	
     3	/// The single global clock (§5). Every animated value is a function of `simTime`.
     4	/// `timeScale` is written by the control-panel slider (§7) and the hyperspace jump (§7b).
     5	@MainActor
     6	final class AnimationClock {
     7	    private(set) var simTime: Double = 0
     8	    var timeScale: Double = 1.0            // 0 = freeze … ~10x (open decision §11 #5)
     9	
    10	    func advance(_ realDelta: Double) { simTime += realDelta * timeScale }
    11	
    12	    /// Restore point for saved locations (§7e).
    13	    func restore(simTime: Double, timeScale: Double) {
    14	        self.simTime = simTime
    15	        self.timeScale = timeScale
    16	    }
    17	}
    18	
    19	/// ECS system that advances the clock each frame so layer systems can sample it.
    20	struct AnimationClockSystem: System {
    21	    init(scene: Scene) {}
    22	    func update(context: SceneUpdateContext) {
    23	        // TODO: advance the shared AnimationClock by context.deltaTime, then let layer
    24	        //       systems read clock.simTime (§5). Provide the clock via a shared handle
    25	        //       (e.g. a scene-level component) rather than a global.
    26	    }
    27	}
    28	","filePath":"Float/Float/Animation/AnimationClock.swift","fileSize":1072,"linesRead":28,"startLine":1,"totalLines":28}

