{"content":"     1	import RealityKit
     2	import simd
     3	
     4	/// §7c hero bodies at a fixed viewing distance (no surface LOD).
     5	enum CelestialBodies {
     6	    static func make(_ cfg: BodyConfig, gen: EnvironmentGenerator) -> Entity {
     7	        switch cfg.kind {
     8	        case .star: return makeStar(cfg, gen: gen)
     9	        default:    return makePlanet(cfg, gen: gen)
    10	        }
    11	    }
    12	
    13	    // Planet: single equirect texture + directional star light (terminator) + optional atmosphere + rings.
    14	    static func makePlanet(_ cfg: BodyConfig, gen: EnvironmentGenerator) -> Entity {
    15	        let e = Entity(); e.name = "Planet"
    16	        e.position = [0, 0, -cfg.distance]
    17	        // TODO: textured sphere; DirectionalLight from the local star for the day/night
    18	        //       terminator (§7c); fresnel-rim atmosphere shell; optional cloud shell;
    19	        //       slow spin driven off the clock.
    20	        if cfg.hasRings { e.addChild(Rings.make(cfg, gen: gen)) }
    21	        return e
    22	    }
    23	
    24	    // Star / Sun — emissive + corona + flares, LUMINANCE CAPPED (§7c, §9 eye-strain).
    25	    static func makeStar(_ cfg: BodyConfig, gen: EnvironmentGenerator) -> Entity {
    26	        let e = Entity(); e.name = "Star"
    27	        e.position = [0, 0, -cfg.distance]
    28	        // TODO: emissive sphere (granulation shader), corona sprites, occasional flares.
    29	        //       CAP peak luminance + angular size; contain bloom (§9).
    30	        return e
    31	    }
    32	}
    33	
    34	/// §7c two-tier rings: textured bulk band + close-resolvable instanced debris.
    35	enum Rings {
    36	    static func make(_ cfg: BodyConfig, gen: EnvironmentGenerator) -> Entity {
    37	        let e = Entity(); e.name = "Rings"
    38	        // TODO: flat textured annulus (bulk band, Cassini gaps).
    39	        // TODO: if cfg.ringsResolveClose — LOD-gated instanced rock belt on the near arc,
    40	        //       reusing the AsteroidField instancing; in-plane orbit off the clock. Near
    41	        //       debris honors the §7d safety bubble if the vantage is inside the ring plane.
    42	        return e
    43	    }
    44	}
    45	","filePath":"Float/Float/Bodies/CelestialBodies.swift","fileSize":1976,"linesRead":45,"startLine":1,"totalLines":45}

